// ==UserScript==
// @name         EMS Roster Tool (Fetch + PDF) — VCEMSA Completion Roster
// @namespace    https://safetyunlimited.local/ems-tools
// @version      4.11.0
// @description  Fetches enrolled students' home addresses from the OTS API, lets you review/edit them and the form header, then generates the filled VCEMSA EMT Course Completion Roster PDF.
// @author       Safety Unlimited
// @match        https://admin2025.otsystems.net/training/classroom/session/*/students*
// @match        https://admin2025.otsystems.net/training/classroom/session/*
// @grant        GM_xmlhttpRequest
// @grant        GM_addStyle
// @connect      api.otsystems.net
// @connect      otsystems.net
// @require      https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js
// @require      https://cdn.jsdelivr.net/npm/pdf-lib/dist/pdf-lib.min.js
// @run-at       document-idle
// ==/UserScript==

(function () {
  'use strict';

  const BRAND = '#1a3a5c';
  const API_BASE = 'https://api.otsystems.net';
  const REQ_DELAY_MS = 250;
  const SSN_CONCURRENCY = 5; // parallel SSN fetches
  const ENROLL_URL = 'https://otsystems.net/admin/students/dashboard/classes/api/JSON_Classes.asp';
  const EMT_CATALYST_ID = 700;
  if (window.pdfjsLib) {
    pdfjsLib.GlobalWorkerOptions.workerSrc =
      'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
  }
  const FORM_PDF_B64 = "";

  /* ============================================================
   *  STYLES
   * ============================================================ */
  GM_addStyle(`
    #ems-panel{position:fixed;top:60px;right:20px;width:640px;max-height:88vh;background:#fff;
      border:1px solid #d4dbe3;border-radius:10px;box-shadow:0 8px 30px rgba(0,0,0,.22);
      z-index:2147483600;font-family:-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif;
      display:flex;flex-direction:column;overflow:hidden;}
    #ems-panel *{box-sizing:border-box;}
    #ems-head{background:${BRAND};color:#fff;padding:11px 14px;display:flex;align-items:center;
      justify-content:space-between;cursor:move;user-select:none;}
    #ems-head h3{margin:0;font-size:14px;font-weight:600;color:#fff !important;}
    #ems-head .ems-hbtns{display:flex;gap:6px;}
    #ems-head button{background:rgba(255,255,255,.15);border:none;color:#fff;width:26px;height:26px;
      border-radius:6px;cursor:pointer;font-size:15px;line-height:1;display:flex;align-items:center;justify-content:center;}
    #ems-head button:hover{background:rgba(255,255,255,.32);}
    #ems-body{padding:14px;overflow:auto;}
    .ems-row{display:flex;gap:8px;margin-bottom:10px;align-items:center;}
    .ems-btn{background:${BRAND};color:#fff;border:none;border-radius:7px;padding:9px 14px;
      font-size:13px;font-weight:600;cursor:pointer;flex:1;}
    .ems-btn:hover{background:#234a73;}
    .ems-btn:disabled{opacity:.5;cursor:not-allowed;}
    .ems-btn.secondary{background:#e8edf2;color:${BRAND};}
    .ems-btn.secondary:hover{background:#dbe3ec;}
    .ems-opt{font-size:12px;color:#3c4a57;}
    .ems-opt label{display:flex;align-items:center;gap:6px;cursor:pointer;}
    #ems-prog-wrap{display:none;margin-bottom:10px;}
    #ems-prog-bg{background:#e8edf2;border-radius:6px;height:10px;overflow:hidden;}
    #ems-prog-bar{background:${BRAND};height:100%;width:0%;transition:width .25s;}
    #ems-prog-text{font-size:11.5px;color:#5a6b7b;margin-top:5px;}
    #ems-count{font-size:11.5px;color:#5a6b7b;margin:4px 0 10px;}
    /* review screen */
    .ems-sec-title{font-size:12px;font-weight:700;color:${BRAND};text-transform:uppercase;
      letter-spacing:.4px;margin:14px 0 8px;border-bottom:1px solid #e1e7ed;padding-bottom:4px;}
    .ems-fields{display:grid;grid-template-columns:1fr 1fr;gap:8px;}
    .ems-field{display:flex;flex-direction:column;gap:3px;}
    .ems-field.full{grid-column:1 / -1;}
    .ems-field label{font-size:10.5px;color:#5a6b7b;font-weight:600;}
    .ems-field input,.ems-field select{border:1px solid #cfd8e0;border-radius:5px;padding:5px 7px;font-size:12px;font-family:inherit;}
    .ems-field input[type=date]{font-family:inherit;color:#3c4a57;}
    .ems-field input:focus,.ems-field select:focus{outline:none;border-color:${BRAND};}
    /* instructor rows */
    .ems-instr-sub{font-size:11px;font-weight:700;color:#5a6b7b;margin:10px 0 4px;}
    .ems-instr-row{display:flex;align-items:flex-end;gap:12px;margin-bottom:7px;}
    .ems-instr-name{flex:1;display:flex;flex-direction:column;gap:3px;}
    .ems-instr-name label{font-size:10.5px;color:#5a6b7b;font-weight:600;}
    .ems-instr-name input{border:1px solid #cfd8e0;border-radius:5px;padding:5px 7px;font-size:12px;font-family:inherit;width:100%;}
    .ems-instr-name input:focus{outline:none;border-color:${BRAND};}
    .ems-certs{display:flex;gap:10px;flex:0 0 auto;padding-bottom:5px;}
    .ems-cert{display:flex;align-items:center;gap:3px;font-size:11px;color:#3c4a57;cursor:pointer;white-space:nowrap;}
    .ems-cert input{cursor:pointer;}
    .ems-students{margin-top:4px;}
    .ems-srow{border:1px solid #e1e7ed;border-radius:7px;padding:8px;margin-bottom:8px;}
    .ems-srow.flag{border-color:#e8b4b4;background:#fff7f7;}
    .ems-srow .ems-srow-head{display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;}
    .ems-srow .ems-srow-num{font-size:11px;font-weight:700;color:${BRAND};}
    .ems-stattxt{font-size:10px;font-weight:700;vertical-align:middle;}
    .ems-progtxt{font-size:10px;font-weight:700;vertical-align:middle;}
    .ems-progdate{font-size:9.5px;color:#5a6b7b;font-weight:600;vertical-align:middle;}
    .ems-sep{color:#aab4bd;font-weight:600;vertical-align:middle;}
    .ems-ssn-warn{font-size:9.5px;color:#c0392b;font-weight:600;margin-top:3px;line-height:1.3;}
    .ems-srow .ems-srow-del{background:none;border:none;color:#c0392b;cursor:pointer;font-size:12px;padding:2px 6px;border-radius:4px;}
    .ems-srow .ems-srow-del:hover{background:#fdeaea;}
    .ems-grid3{display:grid;grid-template-columns:2fr 2fr 0.7fr;gap:5px;margin-bottom:5px;}
    .ems-grid-addr{display:grid;grid-template-columns:3fr 1fr;gap:5px;margin-bottom:5px;}
    .ems-grid-city{display:grid;grid-template-columns:2fr 0.7fr 1fr;gap:5px;margin-bottom:5px;}
    .ems-srow input{width:100%;border:1px solid #cfd8e0;border-radius:5px;padding:4px 6px;font-size:11.5px;font-family:inherit;}
    .ems-srow input::placeholder{color:#aab4bd;}
    .ems-srow input:focus{outline:none;border-color:${BRAND};}
    .ems-mini{font-size:9.5px;color:#8a98a6;margin-bottom:2px;font-weight:600;text-transform:uppercase;letter-spacing:.3px;}
    /* launcher button (sits next to Enrolled Students heading) */
    #ems-launch{display:inline-flex;align-items:center;gap:6px;background:${BRAND};color:#fff;border:none;
      border-radius:6px;padding:6px 12px;font-size:13px;font-weight:600;cursor:pointer;line-height:1;
      margin-left:10px;vertical-align:middle;
      font-family:-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif;}
    #ems-launch:hover{background:#234a73;}
    #ems-launch svg{width:14px;height:14px;}
  `);

  /* ============================================================
   *  PANEL SHELL
   * ============================================================ */
  const panel = document.createElement('div');
  panel.id = 'ems-panel';
  panel.innerHTML = `
    <div id="ems-head">
      <h3>VCEMS 1100 Roster Tool</h3>
      <div class="ems-hbtns">
        <button id="ems-close" title="Close">&times;</button>
      </div>
    </div>
    <div id="ems-body"></div>`;
  panel.style.display = 'none';
  document.body.appendChild(panel);
  const body = panel.querySelector('#ems-body');
  panel.querySelector('#ems-close').addEventListener('click', () => { panel.style.display = 'none'; });

  function openPanel(){
    if(!header.courseEndDate){ const d=scrapeCourseEndDate(); if(d){ header.courseEndDate=d; renderReview(); } }
    panel.style.display = 'flex';
  }

  (function drag(){
    const head = panel.querySelector('#ems-head');
    let d=false,sx,sy,ox,oy;
    head.addEventListener('mousedown',e=>{
      if(e.target.tagName==='BUTTON')return;
      d=true;sx=e.clientX;sy=e.clientY;
      const r=panel.getBoundingClientRect();ox=r.left;oy=r.top;
      panel.style.right='auto';document.body.style.userSelect='none';
    });
    document.addEventListener('mousemove',e=>{if(!d)return;panel.style.left=ox+(e.clientX-sx)+'px';panel.style.top=oy+(e.clientY-sy)+'px';});
    document.addEventListener('mouseup',()=>{d=false;document.body.style.userSelect='';});
  })();

  /* ============================================================
   *  HELPERS + API
   * ============================================================ */
  const clean = (t)=>{ if(t==null)return''; t=String(t).replace(/\s+/g,' ').trim(); return (t==='--'||t==='-')?'':t; };

  // Date helpers: form wants MM/DD/YYYY; native <input type=date> uses YYYY-MM-DD.
  function toISO(mdy){
    if(!mdy) return '';
    const m = String(mdy).match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
    if(!m) return '';
    const mm=m[1].padStart(2,'0'), dd=m[2].padStart(2,'0');
    return `${m[3]}-${mm}-${dd}`;
  }
  function fromISO(iso){
    if(!iso) return '';
    const m = String(iso).match(/^(\d{4})-(\d{2})-(\d{2})$/);
    if(!m) return '';
    return `${parseInt(m[2],10)}/${parseInt(m[3],10)}/${m[1]}`;
  }
  function todayMDY(){
    const d=new Date();
    return `${d.getMonth()+1}/${d.getDate()}/${d.getFullYear()}`;
  }

  // Scrape the course end date from the page's "Date(s):" detail item.
  // Example text: "Tue, May 26, 2026 - Fri, June 26, 2026" -> returns "6/26/2026".
  function scrapeCourseEndDate(){
    let txt='';
    // find a detail-item whose <strong> says "Date(s):"
    const items=document.querySelectorAll('.detail-item');
    for(const it of items){
      const strong=it.querySelector('strong');
      if(strong && /date\(s\)/i.test(strong.textContent||'')){
        const span=it.querySelector('span');
        txt=clean(span?span.textContent:it.textContent);
        break;
      }
    }
    if(!txt) return '';
    // take the part after the last dash/hyphen separator = end date
    const parts=txt.split(/\s[-\u2013\u2014]\s/); // " - ", en/em dash
    const endStr=clean(parts[parts.length-1]);
    // parse "Fri, June 26, 2026" or "June 26, 2026" or "Jun 26, 2026"
    const m=endStr.match(/([A-Za-z]+)\s+(\d{1,2}),?\s+(\d{4})/);
    if(!m) return '';
    const months={january:1,february:2,march:3,april:4,may:5,june:6,july:7,august:8,september:9,october:10,november:11,december:12,
      jan:1,feb:2,mar:3,apr:4,jun:6,jul:7,aug:8,sep:9,sept:9,oct:10,nov:11,dec:12};
    const mo=months[m[1].toLowerCase()];
    if(!mo) return '';
    return `${mo}/${parseInt(m[2],10)}/${m[3]}`;
  }

  function getToken(){ const m=document.cookie.match(/(?:^|;\s*)security-token=([^;]+)/); return m?decodeURIComponent(m[1]):''; }

  function getStudentRows(){
    const rows=[];
    document.querySelectorAll('table tbody tr').forEach(tr=>{
      const link=tr.querySelector('a[href*="student_number="]'); if(!link)return;
      const m=link.href.match(/student_number=(\d+)/i); if(!m)return;
      const statusEl=tr.querySelector('td:nth-child(3) .badge, td:nth-child(3) span');
      const progCell=tr.querySelector('.progress-cell');
      let progress='', progLabel='', progDate='';
      if(progCell){
        const pl=progCell.querySelector('.progress-label');
        const pd=progCell.querySelector('.progress-date');
        progLabel=pl?clean(pl.textContent):'';
        progDate=pd?clean(pd.textContent):'';
        progress=[progLabel,progDate].filter(Boolean).join(' ');
        if(!progress){ progress=clean(progCell.textContent); progLabel=progress; }
      }
      const emailLink=tr.querySelector('a[href^="mailto:"]');
      rows.push({studentNumber:m[1],listName:clean(link.textContent),
        listEmail:emailLink?clean(emailLink.textContent):'',status:statusEl?clean(statusEl.textContent):'',
        progress:progress,progLabel:progLabel,progDate:progDate});
    });
    return rows;
  }

  function apiGet(path,token){
    return new Promise(res=>{
      GM_xmlhttpRequest({method:'GET',url:API_BASE+path,
        headers:{'Accept':'application/json, text/plain, */*','security-token':token},timeout:20000,
        onload:r=>{ if(r.status<200||r.status>=300)return res(null); try{res(JSON.parse(r.responseText));}catch(_){res(null);} },
        onerror:()=>res(null),ontimeout:()=>res(null)});
    });
  }
  function fromV3(j){
    if(!j||typeof j!=='object')return null;
    if(j.address1===undefined&&j.lastName===undefined)return null;
    return {first:clean(j.firstName),last:clean(j.lastName),mi:clean(j.middleInitial),suffix:clean(j.nameSuffix),
      street:clean(j.address1),apt:clean(j.address2),city:clean(j.city),state:clean(j.state),zip:clean(j.zip),
      email:clean(j.email)||clean(j.addEmail)};
  }
  function fromV2(j){
    const rec=Array.isArray(j)?(j[0]&&j[0].Student):(j&&j.Student); if(!rec)return null;
    return {first:clean(rec.FirstName),last:clean(rec.LastName),mi:clean(rec.MiddleInitial),suffix:clean(rec.NameSuffix),
      street:clean(rec.StreetLine1),apt:clean(rec.StreetLine2),city:clean(rec.City),state:clean(rec.Province),
      zip:clean(rec.PostalCode),email:clean(rec.EmailAddress)||clean(rec.AdditionalEmailAddress)};
  }
  async function fetchStudent(num,token){
    let rec=fromV3(await apiGet(`/legacy/v3/student/${num}/details`,token));
    if(rec&&(rec.street||rec.city||rec.zip))return rec;
    const rec2=fromV2(await apiGet(`/Admin/v2/customerSession/activeStudents/${num}`,token));
    if(rec2&&(rec2.street||rec2.city||rec2.zip))return rec2;
    return rec||rec2||null;
  }

  // --- SSN last-4 pipeline ---------------------------------------------------
  // Resolve a student's EMT agreement GUID via the dashboard getenrollments call.
  function resolveAgreementGUID(studentNumber, token){
    return new Promise(resolve=>{
      GM_xmlhttpRequest({
        method:'POST',
        url:ENROLL_URL,
        headers:{'Content-Type':'application/json','Accept':'application/json, text/plain, */*','security-token':token},
        data:JSON.stringify({FormAction:'getenrollments', StudentNumber:String(studentNumber)}),
        timeout:25000,
        onload:r=>{
          if(r.status<200||r.status>=300){ resolve({guid:'', err:'enroll HTTP '+r.status}); return; }
          let j; try{ j=JSON.parse(r.responseText); }catch(_){ resolve({guid:'', err:'enroll bad JSON'}); return; }
          const obj=j&&j.returnObj;
          const list=(obj&&(obj.enrollments||obj.Enrollments))||[];
          if(!Array.isArray(list)||!list.length){ resolve({guid:'', err:'no enrollments'}); return; }
          // find the enrollment whose CatalystsRaw includes CatalystID 700
          const has700=e=>{
            const c=e&&e.CatalystsRaw;
            if(Array.isArray(c)){
              return c.some(x=> x===EMT_CATALYST_ID ||
                (x&&(x.CatalystID===EMT_CATALYST_ID||x.catalystID===EMT_CATALYST_ID||x.CatalystId===EMT_CATALYST_ID)));
            }
            return false;
          };
          let emt=list.find(has700);
          // fallback: match by EMT agreement course name if no catalyst marker present
          if(!emt) emt=list.find(e=>/EMT\s*Agreement|Enrollment Agreement|Emergency Medical Technician/i.test(e&&e.Course_Name||''));
          if(!emt || !emt.EnrollmentId){ resolve({guid:'', err:'no EMT agreement enrollment'}); return; }
          resolve({guid:emt.EnrollmentId, err:''});
        },
        onerror:()=>resolve({guid:'', err:'enroll network error'}),
        ontimeout:()=>resolve({guid:'', err:'enroll timeout'})
      });
    });
  }

  // Fetch the agreement PDF for a GUID and extract the SSN last-4.
  function fetchSSN4ByGUID(guid, token){
    return new Promise(resolve=>{
      const g=(guid||'').trim();
      if(!g){ resolve({ok:false, ssn4:'', err:'no GUID'}); return; }
      if(!window.pdfjsLib){ resolve({ok:false, ssn4:'', err:'pdf.js not loaded'}); return; }
      GM_xmlhttpRequest({
        method:'GET',
        url:`${API_BASE}/legacy/v3/emtagreement/${g}/generatePDF/agreement`,
        headers:{'Accept':'application/pdf','security-token':token},
        responseType:'arraybuffer',
        timeout:30000,
        onload: async r=>{
          if(r.status<200||r.status>=300){ resolve({ok:false, ssn4:'', err:'PDF HTTP '+r.status}); return; }
          try{
            const pdf=await pdfjsLib.getDocument({data:new Uint8Array(r.response)}).promise;
            let full='';
            const pages=Math.min(pdf.numPages,1); // SSN is on page 1
            for(let p=1;p<=pages;p++){
              const page=await pdf.getPage(p);
              const tc=await page.getTextContent();
              full+=tc.items.map(i=>i.str).join(' ')+'\n';
            }
            const m=full.match(/Last\s*4\s*Social\s*Security\s*Number:?\s*(\d{4})/i);
            const nm=full.match(/Student\s*Name:?\s*([A-Za-z.,'\-]+(?:\s+[A-Za-z.,'\-]+){0,4}?)\s+(?:Phone|Address|Start\s*Date)/i);
            const pdfName=nm?nm[1].replace(/\s+/g,' ').trim():'';
            resolve({ok:!!m, ssn4:m?m[1]:'', pdfName:pdfName, err:m?'':'SSN not found in PDF'});
          }catch(e){ resolve({ok:false, ssn4:'', err:'PDF parse error'}); }
        },
        onerror:()=>resolve({ok:false, ssn4:'', err:'PDF network error'}),
        ontimeout:()=>resolve({ok:false, ssn4:'', err:'PDF timeout'})
      });
    });
  }

  // Full chain for one student: number -> GUID -> SSN last-4.
  // Accepts an optional cachedGUID to skip the enrollments lookup, and retries once on failure.
  async function fetchSSN4ForStudent(studentNumber, token, cachedGUID){
    let guid=(cachedGUID||'').trim();
    if(!guid){
      let g=await resolveAgreementGUID(studentNumber, token);
      if(!g.guid){ // one retry on the lookup
        await new Promise(r=>setTimeout(r,400));
        g=await resolveAgreementGUID(studentNumber, token);
      }
      if(!g.guid) return {ok:false, ssn4:'', guid:'', err:g.err};
      guid=g.guid;
    }
    let s=await fetchSSN4ByGUID(guid, token);
    if(!s.ok){ // one retry on the PDF fetch/parse
      await new Promise(r=>setTimeout(r,400));
      s=await fetchSSN4ByGUID(guid, token);
    }
    return {ok:s.ok, ssn4:s.ssn4, guid:guid, pdfName:s.pdfName||'', err:s.err};
  }

  // Compare the roster name to the name printed inside the agreement PDF.
  // Token-aware: handles multi-word surnames (e.g. "San Jose") and middle initials.
  // Returns true if they plausibly match.
  function namesMatch(rosterFirst, rosterLast, pdfName){
    const norm=x=>(x||'').toLowerCase().replace(/[^a-z\s]/g,' ').replace(/\s+/g,' ').trim();
    const pf=norm(pdfName);
    const pdfTokens=pf.split(' ').filter(Boolean);
    const lastTokens=norm(rosterLast).split(' ').filter(Boolean);
    const firstTokens=norm(rosterFirst).split(' ').filter(Boolean);
    if(!pdfTokens.length || (!lastTokens.length && !firstTokens.length)) return true; // not enough info
    // every word of the roster last name should appear among the PDF tokens
    const lastOk = lastTokens.length ? lastTokens.every(t=>pdfTokens.includes(t)) : true;
    // the roster first name (or its initial) should appear among the PDF tokens
    const rf = firstTokens[0] || '';
    const firstOk = rf ? pdfTokens.some(t=> t===rf || t[0]===rf[0]) : true;
    return lastOk && firstOk;
  }

  // Run async tasks with a bounded concurrency pool.
  async function runPool(items, limit, worker, onProgress){
    let idx=0, done=0;
    const total=items.length;
    async function next(){
      while(idx<total){
        const my=idx++;
        await worker(items[my], my);
        done++;
        if(onProgress) onProgress(done, total);
      }
    }
    const runners=[];
    for(let k=0;k<Math.min(limit,total);k++) runners.push(next());
    await Promise.all(runners);
  }

  // Batch: fill SSN last-4 for every student that doesn't already have one.
  async function fetchAllSSNs(){
    const token=getToken();
    const btn=body.querySelector('#ems-fetch-ssn');
    const wrap=body.querySelector('#ems-prog-wrap');
    const bar=body.querySelector('#ems-prog-bar');
    const ptext=body.querySelector('#ems-prog-text');
    if(!token){ if(ptext){ptext.textContent='Could not read security-token cookie. Are you logged in?';} return; }
    if(!students.length){ if(ptext){ptext.textContent='Fetch students first.';} return; }
    if(btn) btn.disabled=true;
    if(wrap) wrap.style.display='block';
    let ok=0, fail=0;
    const targets=students.map((s,i)=>({s,i})).filter(o=>!o.s.ssn4 && o.s.studentNumber);
    if(!targets.length){ if(ptext){ptext.textContent='All students already have an SSN last-4.';} if(btn) btn.disabled=false; return; }
    if(bar) bar.style.width='0%';
    await runPool(targets, SSN_CONCURRENCY, async ({s,i})=>{
      const res=await fetchSSN4ForStudent(s.studentNumber, token, s.guid);
      if(res.ok){ students[i].ssn4=res.ssn4; students[i].guid=res.guid;
        students[i].ssnMismatch = !namesMatch(students[i].first, students[i].last, res.pdfName);
        students[i].pdfName = res.pdfName||''; ok++; }
      else { students[i].guid=res.guid||students[i].guid; fail++; }
    }, (done,total)=>{
      if(bar) bar.style.width=`${Math.round(done/total*100)}%`;
      if(ptext) ptext.textContent=`SSN ${done} of ${total} done`;
    });
    if(bar) bar.style.width='100%';
    if(ptext) ptext.textContent=`SSN done: ${ok} found`+(fail?`, ${fail} not found`:'');
    if(btn) btn.disabled=false;
    renderStudentRows();
  }

  /* ============================================================
   *  STATE
   * ============================================================ */
  let students = [];   // editable student records
  // Each instructor: { name, cert } where cert is one of MD / RN / Paramedic / Other (or '')
  const mkInstr = () => ({ name:'', cert:'' });
  let header = {
    programName:'Safety Unlimited, Inc.', type:'Initial', programDirector:'Julius Griggs', courseEndDate:'',
    primaryInstructor: mkInstr(),
    clinicalCoordinator: mkInstr(),
    assistingInstructors: [mkInstr(), mkInstr(), mkInstr()],
    practicalInstructors: [mkInstr(), mkInstr(), mkInstr()],
    totalEnrolled:'', totalCompleted:'', signatureDate: todayMDY()
  };
  let hasFetched = false;

  /* ============================================================
   *  CERT OPTIONS
   * ============================================================ */
  const CERTS = ['MD','RN','Paramedic','Other'];

  function certRadios(groupId, current){
    return `<div class="ems-certs" data-group="${groupId}">` +
      CERTS.map(c=>`<label class="ems-cert"><input type="radio" name="${groupId}" value="${c}"${current===c?' checked':''}> ${c}</label>`).join('') +
      `</div>`;
  }

  /* ============================================================
   *  HOME SCREEN: REVIEW + EDIT (with inline Fetch)
   * ============================================================ */
  function renderReview(){
    const h=header;
    const instrLine = (label, idAttr, instr) =>
      `<div class="ems-instr-row">
         <div class="ems-instr-name">
           <label>${label}</label>
           <input data-instr="${idAttr}" value="${esc(instr.name)}">
         </div>
         ${certRadios('cert-'+idAttr, instr.cert)}
       </div>`;

    body.innerHTML = `
      <div class="ems-row" style="margin-bottom:6px;">
        <button class="ems-btn" id="ems-fetch" style="flex:1;">${hasFetched?'Re-fetch All':'Fetch Addresses + SSNs'}</button>${hasFetched?'<button class="ems-btn" id="ems-fetch-ssn" style="flex:1;background:#1a3a5c;">Fetch all SSNs</button>':''}
      </div>
      <div id="ems-prog-wrap" style="display:none;margin-bottom:10px;">
        <div id="ems-prog-bg"><div id="ems-prog-bar"></div></div><div id="ems-prog-text"></div>
      </div>
      <div id="ems-count"></div>

      <div class="ems-sec-title">Form Header (Page 1)</div>
      <div class="ems-fields">
        <div class="ems-field full"><label>Program Name</label><input id="h-programName" value="${esc(h.programName)}"></div>
        <div class="ems-field"><label>Type</label>
          <select id="h-type"><option${h.type==='Initial'?' selected':''}>Initial</option><option${h.type==='Recert'?' selected':''}>Recert</option></select></div>
        <div class="ems-field"><label>Course End Date</label><input type="date" id="h-courseEndDate" value="${esc(toISO(h.courseEndDate))}"></div>
        <div class="ems-field full"><label>Program Director</label><input id="h-programDirector" value="${esc(h.programDirector)}"></div>
      </div>

      <div class="ems-sec-title">Instructors</div>
      ${instrLine('Primary Instructor','primary', h.primaryInstructor)}
      ${instrLine('Clinical Coordinator','clinical', h.clinicalCoordinator)}
      <div class="ems-instr-sub">Assisting Instructors</div>
      ${h.assistingInstructors.map((ins,i)=>instrLine('', 'assist'+i, ins)).join('')}
      <div class="ems-instr-sub">Practical Instructors (skills)</div>
      ${h.practicalInstructors.map((ins,i)=>instrLine('', 'pract'+i, ins)).join('')}

      <div class="ems-fields" style="margin-top:12px;">
        <div class="ems-field"><label># Enrolled (day 1)</label><input id="h-totalEnrolled" value="${esc(h.totalEnrolled)}"></div>
        <div class="ems-field"><label># Completed</label><input id="h-totalCompleted" value="${esc(h.totalCompleted)}"></div>
        <div class="ems-field"><label>Signature Date</label><input type="date" id="h-signatureDate" value="${esc(toISO(h.signatureDate))}"></div>
      </div>

      <div class="ems-sec-title">Students (<span id="ems-scount">${students.length}</span>)</div>
      <div class="ems-students" id="ems-students"></div>
      <button class="ems-btn secondary" id="ems-add" style="margin-bottom:12px;">+ Add student</button>

      <div class="ems-row">
        <button class="ems-btn" id="ems-gen">Generate PDF</button>
      </div>
      <div id="ems-genmsg" style="font-size:11.5px;color:#5a6b7b;margin-top:8px;"></div>`;

    // simple text/select header bindings
    ['programName','type','programDirector','totalEnrolled','totalCompleted']
      .forEach(k=>{ const el=body.querySelector('#h-'+k); el.addEventListener('input',()=>{header[k]=el.value;}); });
    // date inputs: native picker gives YYYY-MM-DD; store as MM/DD/YYYY for the form
    ['courseEndDate','signatureDate'].forEach(k=>{
      const el=body.querySelector('#h-'+k);
      el.addEventListener('change',()=>{ header[k]=fromISO(el.value); });
    });

    // instructor name bindings
    body.querySelectorAll('input[data-instr]').forEach(el=>{
      el.addEventListener('input',()=>setInstr(el.dataset.instr,'name',el.value));
    });
    // instructor cert radio bindings
    body.querySelectorAll('.ems-certs input[type=radio]').forEach(el=>{
      el.addEventListener('change',()=>{
        const id=el.name.replace(/^cert-/,'');
        setInstr(id,'cert',el.value);
      });
    });

    renderStudentRows();
    body.querySelector('#ems-add').addEventListener('click',()=>{
      students.push({last:'',first:'',mi:'',suffix:'',ssn4:'',street:'',apt:'',city:'',state:'',zip:'',email:'',status:'',studentNumber:''});
      renderStudentRows(); updateCount();
    });
    body.querySelector('#ems-gen').addEventListener('click',generatePDF);
    body.querySelector('#ems-fetch').addEventListener('click', runFetch);
    { const _ssnBtn=body.querySelector('#ems-fetch-ssn'); if(_ssnBtn) _ssnBtn.addEventListener('click', fetchAllSSNs); }
  }

  // Map an instr id like 'primary','clinical','assist0','pract2' to its state object and set a field.
  function setInstr(id, key, val){
    if(id==='primary') header.primaryInstructor[key]=val;
    else if(id==='clinical') header.clinicalCoordinator[key]=val;
    else if(id.startsWith('assist')) header.assistingInstructors[+id.slice(6)][key]=val;
    else if(id.startsWith('pract')) header.practicalInstructors[+id.slice(5)][key]=val;
  }

  function updateCount(){
    const el=body.querySelector('#ems-scount'); if(el) el.textContent=students.length;
  }

  async function runFetch(){
    const fetchBtn=body.querySelector('#ems-fetch');
    const skip=false; // always include all students
    const wrap=body.querySelector('#ems-prog-wrap');
    const bar=body.querySelector('#ems-prog-bar');
    const ptext=body.querySelector('#ems-prog-text');
    const count=body.querySelector('#ems-count');
    fetchBtn.disabled=true; wrap.style.display='block';

    const token=getToken();
    if(!token){ ptext.textContent='Could not read security-token cookie. Are you logged in?'; fetchBtn.disabled=false; return; }

    let rows=getStudentRows();
    if(skip) rows=rows.filter(s=>/active/i.test(s.status));
    if(!rows.length){ ptext.textContent='No matching students found on this page.'; fetchBtn.disabled=false; return; }

    students=[];
    for(let i=0;i<rows.length;i++){
      const s=rows[i];
      bar.style.width=`${Math.round(i/rows.length*100)}%`;
      ptext.textContent=`Fetching ${i+1} of ${rows.length}: ${s.listName}`;
      const rec=await fetchStudent(s.studentNumber,token)||{};
      let f=rec.first||'',l=rec.last||'';
      if(!f&&!l&&s.listName){ const p=s.listName.split(' ').filter(Boolean); f=p[0]||''; l=p.slice(1).join(' '); }
      students.push({last:l,first:f,mi:rec.mi||'',suffix:rec.suffix||'',ssn4:'',guid:'',
        street:rec.street||'',apt:rec.apt||'',city:rec.city||'',state:rec.state||'',zip:rec.zip||'',
        email:rec.email||s.listEmail||'',status:s.status,progress:s.progress||'',progLabel:s.progLabel||'',progDate:s.progDate||'',studentNumber:s.studentNumber});
      if(i<rows.length-1) await new Promise(r=>setTimeout(r,REQ_DELAY_MS));
    }
    bar.style.width='100%';
    hasFetched=true;
    // Always continue into SSN fetching after addresses.
    {
      const ssnTargets=students.map((s,i)=>({s,i})).filter(o=>!o.s.ssn4 && o.s.studentNumber);
      if(ssnTargets.length){
        bar.style.width='0%';
        ptext.textContent=`Fetching SSNs: 0 of ${ssnTargets.length}`;
        await runPool(ssnTargets, SSN_CONCURRENCY, async ({s,i})=>{
          const res=await fetchSSN4ForStudent(s.studentNumber, token, s.guid);
          if(res.ok){ students[i].ssn4=res.ssn4; students[i].guid=res.guid;
            students[i].ssnMismatch = !namesMatch(students[i].first, students[i].last, res.pdfName);
            students[i].pdfName = res.pdfName||''; }
          else { students[i].guid=res.guid||students[i].guid; }
        }, (done,total)=>{ if(bar) bar.style.width=`${Math.round(done/total*100)}%`; ptext.textContent=`Fetching SSNs: ${done} of ${total}`; });
        bar.style.width='100%';
      }
    }
    if(!header.totalEnrolled) header.totalEnrolled=String(students.length);
    const missing=students.filter(r=>!r.street||!r.city||!r.zip).length;
    count.innerHTML=`Fetched ${students.length} students`+(missing?` &middot; <span style="color:#c0392b">${missing} missing address</span>`:'');
    // re-render to reflect new students + populated totals, keeping all header edits
    renderReview();
  }

  function renderStudentRows(){
    const wrap=body.querySelector('#ems-students');
    wrap.innerHTML='';
    students.forEach((s,idx)=>{
      const miss=!s.street||!s.city||!s.zip;
      const row=document.createElement('div');
      row.className='ems-srow'+(miss?' flag':'');
      row.innerHTML=`
        <div class="ems-srow-head">
          <span class="ems-srow-num">#${idx+1}${s.studentNumber?' · S#'+s.studentNumber:''}${(()=>{
            const statusColor = /active/i.test(s.status)?'rgb(13,110,253)':(/refund/i.test(s.status)?'rgb(13,202,240)':(/pending/i.test(s.status)?'rgb(255,193,7)':''));
            const progColor = /complete/i.test(s.progLabel)?'rgb(25,135,84)':(/fail/i.test(s.progLabel)?'rgb(111,66,193)':'');
            const statHtml = s.status?`<span class="ems-stattxt" style="${statusColor?`color:${statusColor};`:''}">${esc(s.status)}</span>`:'';
            const progLblHtml = s.progLabel?`<span class="ems-progtxt" style="${progColor?`color:${progColor};`:''}">${esc(s.progLabel)}</span>`:'';
            const progDtHtml = s.progDate?` <span class="ems-progdate">${esc(s.progDate)}</span>`:'';
            const progHtml = (progLblHtml||progDtHtml)?`${progLblHtml}${progDtHtml}`:'';
            if(statHtml && progHtml) return ` ${statHtml} <span class="ems-sep">/</span> ${progHtml}`;
            if(statHtml) return ` ${statHtml}`;
            if(progHtml) return ` ${progHtml}`;
            return '';
          })()}</span>
          <button class="ems-srow-del" data-i="${idx}" title="Remove">Remove</button>
        </div>
        <div class="ems-grid3">
          <div><div class="ems-mini">Last</div><input data-i="${idx}" data-k="last" value="${esc(s.last)}"></div>
          <div><div class="ems-mini">First</div><input data-i="${idx}" data-k="first" value="${esc(s.first)}"></div>
          <div><div class="ems-mini">MI</div><input data-i="${idx}" data-k="mi" value="${esc(s.mi)}" maxlength="4"></div>
        </div>
        <div class="ems-grid-addr">
          <div><div class="ems-mini">Street</div><input data-i="${idx}" data-k="street" value="${esc(s.street)}"></div>
          <div><div class="ems-mini">Apt</div><input data-i="${idx}" data-k="apt" value="${esc(s.apt)}"></div>
        </div>
        <div class="ems-grid-city">
          <div><div class="ems-mini">City</div><input data-i="${idx}" data-k="city" value="${esc(s.city)}"></div>
          <div><div class="ems-mini">State</div><input data-i="${idx}" data-k="state" value="${esc(s.state)}" maxlength="2"></div>
          <div><div class="ems-mini">Zip</div><input data-i="${idx}" data-k="zip" value="${esc(s.zip)}"></div>
        </div>
        <div class="ems-grid-addr">
          <div><div class="ems-mini">Email</div><input data-i="${idx}" data-k="email" value="${esc(s.email)}"></div>
          <div><div class="ems-mini">SSN last 4</div><input data-i="${idx}" data-k="ssn4" value="${esc(s.ssn4)}" maxlength="4" placeholder="optional"${s.ssnMismatch?' style="border-color:#c0392b;background:#fff7f7;"':''}>${s.ssnMismatch?`<div class="ems-ssn-warn">⚠ Agreement name "${esc(s.pdfName||'')}" doesn't match — verify this SSN</div>`:''}</div>
        </div>`;
      wrap.appendChild(row);
    });
    wrap.querySelectorAll('input').forEach(inp=>{
      inp.addEventListener('input',()=>{ const st=students[+inp.dataset.i]; st[inp.dataset.k]=inp.value; if(inp.dataset.k==='ssn4' && st.ssnMismatch){ st.ssnMismatch=false; const warn=inp.parentNode.querySelector('.ems-ssn-warn'); if(warn) warn.remove(); inp.style.borderColor=''; inp.style.background=''; } });
    });
    wrap.querySelectorAll('.ems-srow-del').forEach(btn=>{
      btn.addEventListener('click',()=>{ students.splice(+btn.dataset.i,1); renderStudentRows(); updateCount(); });
    });
  }

  function esc(t){ return (t||'').replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c])); }

  /* ============================================================
   *  PDF GENERATION (overlay onto the flat county form)
   * ============================================================ */
  function b64ToUint8(b64){
    const bin=atob(b64); const len=bin.length; const u=new Uint8Array(len);
    for(let i=0;i<len;i++)u[i]=bin.charCodeAt(i); return u;
  }

  // Per-page roster geometry (pdf-lib bottom-origin, page height 792).
  const ROW_BLOCK_TOPS = [136.9,180.1,223.3,266.5,309.7,352.9,396.1,439.3,482.5,525.5,568.7,611.9];
  const COL = { name:68, ssn:233, contact:301 };
  const STUDENTS_PER_PAGE = 12;

  async function generatePDF(){
    const msg=body.querySelector('#ems-genmsg');
    const genBtn=body.querySelector('#ems-gen');

    // --- completeness check before generating the official roster ---
    {
      const problems=[];
      if(!header.courseEndDate) problems.push('Header: Course End Date is empty');
      if(!header.programDirector) problems.push('Header: Program Director is empty');
      students.forEach((s,i)=>{
        const who=`${(s.first||'').trim()} ${(s.last||'').trim()}`.trim() || `Student #${i+1}`;
        const miss=[];
        if(!(s.first||'').trim()) miss.push('first name');
        if(!(s.last||'').trim()) miss.push('last name');
        if(!(s.street||'').trim()) miss.push('street');
        if(!(s.city||'').trim()) miss.push('city');
        if(!(s.state||'').trim()) miss.push('state');
        if(!(s.zip||'').trim()) miss.push('zip');
        if(!/^\d{4}$/.test((s.ssn4||'').trim())) miss.push('SSN last-4');
        if(miss.length) problems.push(`${who}: missing ${miss.join(', ')}`);
        if(s.ssnMismatch) problems.push(`${who}: ⚠ SSN may belong to "${(s.pdfName||'').trim()}" — verify`);
      });
      if(problems.length){
        const maxShow=15;
        const shown=problems.slice(0,maxShow).join('\n');
        const extra=problems.length>maxShow ? `\n…and ${problems.length-maxShow} more` : '';
        const ok=window.confirm(
          `Some roster information is incomplete (${problems.length} item${problems.length>1?'s':''}):\n\n`+
          shown+extra+
          `\n\nGenerate the PDF anyway?`);
        if(!ok){ if(msg){ msg.style.color='#c0392b'; msg.textContent='Generation cancelled — fill in the missing fields above.'; } return; }
      }
    }

    genBtn.disabled=true; msg.textContent='Building PDF…';
    try{
      const { PDFDocument, StandardFonts, rgb } = PDFLib;
      const srcDoc = await PDFDocument.load(b64ToUint8(FORM_PDF_B64));
      const out = await PDFDocument.create();
      const font = await out.embedFont(StandardFonts.Helvetica);

      // copy page 1 (header) and the two roster template pages
      const [p1] = await out.copyPages(srcDoc,[0]);
      out.addPage(p1);
      fillHeader(p1,font,rgb);

      // how many roster pages do we need?
      const pageCount = Math.max(1, Math.ceil(students.length / STUDENTS_PER_PAGE));
      // template roster page is source index 1 (page 2). Page 3 has the signature line.
      for(let pg=0; pg<pageCount; pg++){
        const isLast = (pg === pageCount-1);
        // use source page 3 (index 2, has signature) for the last page, else page 2 (index 1)
        const srcIndex = isLast ? 2 : 1;
        const [rp] = await out.copyPages(srcDoc,[srcIndex]);
        out.addPage(rp);
        const slice = students.slice(pg*STUDENTS_PER_PAGE,(pg+1)*STUDENTS_PER_PAGE);
        fillRosterPage(rp,font,rgb,slice,isLast);
      }

      const bytes = await out.save();
      const blob = new Blob([bytes],{type:'application/pdf'});
      const url = URL.createObjectURL(blob);
      const a=document.createElement('a');
      a.href=url; a.download=`EMS_Completion_Roster_${new Date().toISOString().slice(0,10)}.pdf`;
      a.click(); URL.revokeObjectURL(url);
      msg.innerHTML=`<span style="color:${BRAND};font-weight:600;">PDF generated (${out.getPageCount()} pages).</span>`;
    }catch(err){
      msg.innerHTML=`<span style="color:#c0392b;">Error: ${esc(err.message||String(err))}</span>`;
    }finally{
      genBtn.disabled=false;
    }
  }

  function draw(page,font,rgb,text,x,topY,size){
    if(!text)return;
    page.drawText(String(text),{x,y:792-topY,size:size||9,font,color:rgb(0.1,0.1,0.12)});
  }
  // Draw with an explicit pdf-lib baseline (y measured from page bottom).
  function drawAt(page,font,rgb,text,x,baselineY,size){
    if(!text)return;
    page.drawText(String(text),{x,y:baselineY,size:size||9,font,color:rgb(0.1,0.1,0.12)});
  }

  // ---- Clean instructor-section rebuild ------------------------------------------------
  // The form's pre-printed instructor area is inconsistent (shifted/missing boxes, varied
  // line lengths, baked-in marks). Instead of patching it, we white out the whole instructor
  // zone once and redraw it cleanly: section labels, uniform name lines, uniform checkboxes
  // (MD/RN/Paramedic/Other) with centered X's. County header/title/bullets/footer untouched.
  // All coordinates here are TOP-ORIGIN (y measured from page top); drawT converts to pdf-lib.
  const PAGE_H = 792;
  function drawT(page,font,rgb,x,top,text,size){      // text at top-origin baseline
    if(text===undefined||text===null||text==='') return;
    page.drawText(String(text),{x,y:PAGE_H-top,size:size||10,font,color:rgb(0,0,0)});
  }
  function lineT(page,rgb,x0,x1,top,w){                // horizontal rule at top-origin y
    page.drawLine({ start:{x:x0,y:PAGE_H-top}, end:{x:x1,y:PAGE_H-top}, thickness:w||0.8, color:rgb(0,0,0) });
  }

  // Checkbox columns: box x + label x for each cert.
  const CERT_COLS = [
    { cert:'MD',        boxX:234, labelX:252 },
    { cert:'RN',        boxX:306, labelX:324 },
    { cert:'Paramedic', boxX:378, labelX:396 },
    { cert:'Other',     boxX:486, labelX:504 }
  ];
  const CB = 10.5;        // checkbox size
  const CBX_W = 6.0, CBX_CAP = 5.96; // "X" glyph metrics at 9pt

  // Draw one instructor row: name on a line, then the four labelled checkboxes centered on the
  // label baseline `labelTop`. `cert` is the selected option (or '').
  function drawInstrRow(page,font,rgb, name, lineTop, labelTop, lineX0, lineX1, cert){
    // name line + name on top of it
    lineT(page,rgb, lineX0, lineX1, lineTop, 0.8);
    drawT(page,font,rgb, lineX0+3, lineTop-2, name, 9);
    // checkboxes
    CERT_COLS.forEach(col=>{
      drawT(page,font,rgb, col.labelX, labelTop, col.cert, 10);
      // box vertically centered on the label cap (cap centre ≈ labelTop-3.3 top-origin)
      const cyTop = labelTop - 3.3;                 // top-origin y of box centre
      const boxBottomPdf = PAGE_H - (cyTop + CB/2); // pdf-lib bottom of box
      page.drawRectangle({ x:col.boxX, y:boxBottomPdf, width:CB, height:CB,
        borderColor:rgb(0,0,0), borderWidth:0.9 });
      if(cert===col.cert){
        const xX = col.boxX + (CB-CBX_W)/2;
        const xY = boxBottomPdf + (CB-CBX_CAP)/2;
        page.drawText('X',{x:xX,y:xY,size:9,font,color:rgb(0,0,0)});
      }
    });
  }

  // Instructor section layout (top-origin). label rows and their name-line rows.
  const SEC = {
    lineX0:49, lineX1:205,
    primary:   { titleTop:398, lineTop:410, labelTop:410, nameLineTop:410 },
    clinical:  { titleTop:430, lineTop:442, labelTop:442 },
    assistTitleTop:462,
    assist:  [ {lineTop:474, labelTop:474}, {lineTop:487.5, labelTop:487.5}, {lineTop:501, labelTop:501} ],
    practTitleTop:524,
    pract:   [ {lineTop:536, labelTop:536}, {lineTop:549.5, labelTop:549.5}, {lineTop:563, labelTop:563} ]
  };

  function fillHeader(page,font,rgb){
    const h=header;
    const DEFAULT_PROGRAM = 'Safety Unlimited, Inc.';
    if(h.programName && h.programName.trim() !== DEFAULT_PROGRAM){
      draw(page,font,rgb,h.programName,210,251,9);
    }
    // The form is pre-printed with "XX" inside the Initial box. White out that area, then:
    //  - Initial selected: draw a fresh clean box + centered X (the original box is removed
    //    by the whiteout since the baked-in XX overlapped it).
    //  - Recert selected: the Recert box is already empty/clean on the form, so just add a
    //    centered X in it (no new box needed).
    const IB=11.04, IXW=6.0, IXCAP=5.96, by=538.78;
    page.drawRectangle({ x:369, y:536, width:14, height:15, color:rgb(1,1,1) });
    if(h.type==='Recert'){
      const rx=432.0;
      drawAt(page,font,rgb,'X', rx+((IB-1)-IXW)/2, by+((IB-1)-IXCAP)/2, 9);
    } else {
      const ix=370.45;
      page.drawRectangle({ x:ix, y:by, width:IB-1, height:IB-1, borderColor:rgb(0,0,0), borderWidth:0.9 });
      drawAt(page,font,rgb,'X', ix+((IB-1)-IXW)/2, by+((IB-1)-IXCAP)/2, 9);
    }

    draw(page,font,rgb,h.programDirector,148,276,9);
    draw(page,font,rgb,h.courseEndDate,418,276,9);

    // ---- Clean rebuild of the instructor section ----
    // White out the whole instructor zone (top 388-585), then redraw cleanly. The county
    // title, bullet instructions, program/director lines, totals and footer are all outside
    // this band and remain untouched.
    page.drawRectangle({ x:45, y:PAGE_H-585, width:520, height:585-388, color:rgb(1,1,1) });

    // Primary
    drawT(page,font,rgb, 49, SEC.primary.titleTop, 'Primary Instructor', 10);
    drawInstrRow(page,font,rgb, h.primaryInstructor.name, SEC.primary.lineTop, SEC.primary.labelTop,
      SEC.lineX0, SEC.lineX1, h.primaryInstructor.cert);
    // Clinical
    drawT(page,font,rgb, 49, SEC.clinical.titleTop, 'Clinical Coordinator', 10);
    drawInstrRow(page,font,rgb, h.clinicalCoordinator.name, SEC.clinical.lineTop, SEC.clinical.labelTop,
      SEC.lineX0, SEC.lineX1, h.clinicalCoordinator.cert);
    // Assisting
    drawT(page,font,rgb, 49, SEC.assistTitleTop, 'Assisting Instructors', 10);
    h.assistingInstructors.forEach((ins,i)=>{
      const g=SEC.assist[i];
      drawInstrRow(page,font,rgb, ins.name, g.lineTop, g.labelTop, SEC.lineX0, SEC.lineX1, ins.cert);
    });
    // Practical
    drawT(page,font,rgb, 49, SEC.practTitleTop, 'Practical Instructors (skills)', 10);
    h.practicalInstructors.forEach((ins,i)=>{
      const g=SEC.pract[i];
      drawInstrRow(page,font,rgb, ins.name, g.lineTop, g.labelTop, SEC.lineX0, SEC.lineX1, ins.cert);
    });

    draw(page,font,rgb,h.totalEnrolled,400,630,9);
    draw(page,font,rgb,h.totalCompleted,400,655,9);
  }

  function fillRosterPage(page,font,rgb,slice,isLast){
    slice.forEach((s,i)=>{
      const top = ROW_BLOCK_TOPS[i];
      const line1 = top + 15;   // name + ssn + contact line 1
      const line2 = top + 36;   // contact line 2
      // Name: "Last, First MI"
      let name = s.last||'';
      if(s.first) name += (name?', ':'')+s.first;
      if(s.mi) name += ' '+s.mi;
      if(s.suffix) name += ' '+s.suffix;
      draw(page,font,rgb,name,COL.name,line1,9);
      // SSN last 4
      draw(page,font,rgb,s.ssn4,COL.ssn+8,line1,9);
      // Contact line 1: full address  (street apt, City, ST Zip)
      let addr = s.street||'';
      if(s.apt) addr += (addr?' ':'')+s.apt;
      if(s.city) addr += (addr?', ':'')+s.city;
      if(s.state) addr += (addr?', ':'')+s.state;
      if(s.zip) addr += (addr?' ':'')+s.zip;
      draw(page,font,rgb,addr,COL.contact,line1,8);
      // Contact line 2: email
      draw(page,font,rgb,s.email,COL.contact,line2,8);
    });
    if(isLast){
      // Page 3's signature Date line is pre-printed with a sample date "02/11/2026" and the
      // underline is made of separate underscore glyphs (broken). To get a clean result:
      //  1) white out the whole date-line strip (x 436-562), removing old date + underscores,
      //  2) draw ONE solid unbroken line across it,
      //  3) place the chosen date resting ON TOP of that line.
      const LINE_Y = 84.5;
      page.drawRectangle({ x:436, y:80, width:126, height:18, color:rgb(1,1,1) });
      page.drawLine({ start:{x:438,y:LINE_Y}, end:{x:560,y:LINE_Y}, thickness:0.8, color:rgb(0,0,0) });
      if(header.signatureDate){
        drawAt(page,font,rgb,header.signatureDate,442,LINE_Y+2,10);
      }
    }
  }


  /* ============================================================
   *  INIT + LAUNCHER INJECTION
   * ============================================================ */
  renderReview();          // build the home (review) screen; panel still hidden
  // Auto-detect the course end date from the page (only if not already set).
  if(!header.courseEndDate){ const _d=scrapeCourseEndDate(); if(_d){ header.courseEndDate=_d; renderReview(); } }

  const LAUNCH_SVG = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" '
    + 'stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="4" width="18" height="14" rx="2"></rect>'
    + '<path d="M3 9h18M8 21h8M12 18v3"></path></svg>';

  function makeLaunchBtn(){
    const b=document.createElement('button');
    b.id='ems-launch';
    b.type='button';
    b.title='Open the EMS Roster Tool';
    b.innerHTML='<span>1100 Roster Tool</span>';
    b.addEventListener('click',openPanel);
    return b;
  }

  // Find the "Enrolled Students" <h5> and place the button right after its count badge.
  function injectLauncher(){
    if(document.getElementById('ems-launch')) return; // already there
    const headings=document.querySelectorAll('h5');
    for(const h of headings){
      if(/Enrolled Students/i.test(h.textContent)){
        const badge=h.querySelector('.badge');
        if(badge) badge.insertAdjacentElement('afterend', makeLaunchBtn());
        else h.appendChild(makeLaunchBtn());
        return;
      }
    }
  }

  injectLauncher();
  // Angular re-renders the list; keep the button present.
  const moTarget=document.querySelector('#content')||document.body;
  new MutationObserver(()=>injectLauncher()).observe(moTarget,{childList:true,subtree:true});

})();